import React from 'react';
import { Select } from '@linm-soft/common-components';
import { VoucherPagerNav } from '../voucher/VoucherPagerNav';
import erp from '../../styles/erpPage.module.css';

export const VOUCHER_LIST_PAGE_SIZES = [20, 50, 100] as const;

export type VoucherListPageSize = (typeof VOUCHER_LIST_PAGE_SIZES)[number];

export const DEFAULT_VOUCHER_LIST_PAGE_SIZE: VoucherListPageSize = 20;

export const VOUCHER_LIST_PAGE_SIZE_OPTIONS = VOUCHER_LIST_PAGE_SIZES.map(n => ({
  value: String(n),
  label: String(n),
}));

export interface VoucherListPaginationProps {
  testIdPrefix: string;
  page: number;
  totalCount: number;
  pageSize: number;
  onPageChange: (page: number) => void;
  onPageSizeChange: (pageSize: number) => void;
}

export const VoucherListPagination: React.FC<VoucherListPaginationProps> = ({
  testIdPrefix,
  page,
  totalCount,
  pageSize,
  onPageChange,
  onPageSizeChange,
}) => {
  const totalPages = Math.max(1, Math.ceil(totalCount / pageSize));
  const safePage = Math.min(Math.max(1, page), totalPages);

  return (
    <div className={erp.paginationRow} data-testid={`${testIdPrefix}-pagination`}>
      <span className={erp.totalCount}>
        Tổng: {totalCount} · Trang {safePage}/{totalPages}
      </span>
      <div className={erp.paginationControls}>
        <div className={erp.paginationPageSize} data-testid={`${testIdPrefix}-field-pageSize`}>
          <span className={erp.paginationPageSizeLabel}>Hiển thị</span>
          <Select
            value={String(pageSize)}
            options={VOUCHER_LIST_PAGE_SIZE_OPTIONS}
            onChange={e => onPageSizeChange(Number(e.target.value))}
            data-testid={`${testIdPrefix}-page-size`}
          />
        </div>
        <VoucherPagerNav
          index={safePage - 1}
          total={totalPages}
          onFirst={() => onPageChange(1)}
          onPrev={() => onPageChange(Math.max(1, safePage - 1))}
          onNext={() => onPageChange(Math.min(totalPages, safePage + 1))}
          onEnd={() => onPageChange(totalPages)}
          testIdPrefix={`${testIdPrefix}-page`}
        />
      </div>
    </div>
  );
};
